// src/routes/user.ts
var userRoutes = new Hono2;
userRoutes.get("/portfolio/:address", async (c2) => {
  const address = c2.req.param("address").toLowerCase();
  const createdCharacters = db2.query.characters.findMany({
    orderBy: desc2(characters.createdAt)
  }).filter((char2) => char2.creator === address);
  return c2.json({
    address,
    created: createdCharacters,
    holdings: []
  });
});
userRoutes.get("/battles/:address", async (c2) => {
  const address = c2.req.param("address").toLowerCase();
  const stakes = db2.query.battleStakes.findMany({
    where: (s2) => s2.staker === address
  });
  const battleIds = [...new Set(stakes.map((s2) => s2.battleId))];
  const userBattles = battleIds.map((id) => db2.query.battles.findFirst({
    where: (b3) => b3.id === id
  })).filter(Boolean);
  return c2.json({
    stakes,
    battles: userBattles
  });
});
userRoutes.get("/stats/:address", async (c2) => {
  const address = c2.req.param("address").toLowerCase();
  const createdCharacters = db2.query.characters.findMany({
    orderBy: desc2(characters.createdAt)
  }).filter((char2) => char2.creator === address);
  const stakesResult = db2.query.battleStakes.findMany({
    where: (s2) => s2.staker === address
  });
  const stakesByBattle = {};
  stakesResult.forEach((s2) => {
    if (!stakesByBattle[s2.battleId])
      stakesByBattle[s2.battleId] = [];
    stakesByBattle[s2.battleId].push(s2);
  });
  let wins = 0;
  let losses = 0;
  let totalStaked = 0;
  let totalWon = 0;
  for (const battleId of Object.keys(stakesByBattle)) {
    const battle = db2.query.battles.findFirst({
      where: (b3) => b3.id === battleId
    });
    if (battle?.status === "RESOLVED" && battle.winner) {
      const userStakes = stakesByBattle[battleId];
      for (const stake of userStakes) {
        totalStaked += parseFloat(stake.amount);
        if (stake.backedCharacter === battle.winner) {
          wins++;
          if (stake.claimedAmount) {
            totalWon += parseFloat(stake.claimedAmount);
          }
        } else {
          losses++;
        }
      }
    }
  }
  return c2.json({
    address,
    charactersCreated: createdCharacters.length,
    battlesParticipated: Object.keys(stakesByBattle).length,
    wins,
    losses,
    winRate: wins + losses > 0 ? wins / (wins + losses) * 100 : 0,
    totalStaked: totalStaked.toFixed(4),
    totalWon: totalWon.toFixed(4),
    pnl: (totalWon - totalStaked).toFixed(4)
  });
});

