// src/services/wallet/okx-api.ts
import crypto4 from "crypto";
var X_LAYER_CHAIN_ID = "196";
var OKB_ADDRESS = "0x0000000000000000000000000000000000000000";

class OkxApiClient {
  config;
  mockMode;
  constructor(config) {
    const apiKey = config?.apiKey || process.env.OKX_API_KEY;
    const secretKey = config?.secretKey || process.env.OKX_SECRET_KEY;
    const passphrase = config?.passphrase || process.env.OKX_PASSPHRASE;
    const projectId = config?.projectId || process.env.OKX_PROJECT_ID;
    this.mockMode = !apiKey || !secretKey || !passphrase || !projectId;
    if (this.mockMode) {
      console.log("[OKX] Running in mock mode - no API credentials configured");
      this.config = {
        apiKey: "",
        secretKey: "",
        passphrase: "",
        projectId: "",
        baseUrl: "https://www.okx.com"
      };
    } else {
      this.config = {
        apiKey,
        secretKey,
        passphrase,
        projectId,
        baseUrl: config?.baseUrl || "https://www.okx.com"
      };
    }
  }
  isMockMode() {
    return this.mockMode;
  }
  sign(timestamp3, method, path2, body = "") {
    const message = timestamp3 + method + path2 + body;
    return crypto4.createHmac("sha256", this.config.secretKey).update(message).digest("base64");
  }
  async request(method, path2, body) {
    if (this.mockMode) {
      throw new Error("OKX API not configured - running in mock mode");
    }
    const timestamp3 = new Date().toISOString();
    const bodyStr = body ? JSON.stringify(body) : "";
    const signature = this.sign(timestamp3, method, path2, bodyStr);
    const headers = {
      "Content-Type": "application/json",
      "OK-ACCESS-KEY": this.config.apiKey,
      "OK-ACCESS-SIGN": signature,
      "OK-ACCESS-TIMESTAMP": timestamp3,
      "OK-ACCESS-PASSPHRASE": this.config.passphrase,
      "OK-ACCESS-PROJECT": this.config.projectId
    };
    const response = await fetch(`${this.config.baseUrl}${path2}`, {
      method,
      headers,
      body: body ? bodyStr : undefined
    });
    if (!response.ok) {
      throw new Error(`OKX API error: ${response.status} ${response.statusText}`);
    }
    return response.json();
  }
  async createWallet(characterTicker) {
    if (this.mockMode) {
      const mockId = `mock_wallet_${characterTicker}_${Date.now()}`;
      const mockAddress = `0x${crypto4.randomBytes(20).toString("hex")}`;
      console.log(`[OKX Mock] Created wallet for ${characterTicker}: ${mockAddress}`);
      return { walletId: mockId, address: mockAddress };
    }
    const response = await this.request("POST", "/api/v5/waas/wallet/create-wallet", {
      walletName: `ALIVE_${characterTicker}`,
      chainId: X_LAYER_CHAIN_ID
    });
    if (response.code !== "0" || !response.data?.[0]) {
      throw new Error(`Failed to create wallet: ${response.msg}`);
    }
    return {
      walletId: response.data[0].walletId,
      address: response.data[0].address
    };
  }
  async getBalance(walletAddress) {
    if (this.mockMode) {
      return {
        okb: "10.5",
        tokens: []
      };
    }
    const response = await this.request("GET", `/api/v5/waas/asset/token-balances?address=${walletAddress}&chainId=${X_LAYER_CHAIN_ID}`);
    if (response.code !== "0") {
      throw new Error(`Failed to get balance: ${response.msg}`);
    }
    const assets = response.data?.[0]?.tokenAssets || [];
    const okbAsset = assets.find((a2) => a2.tokenAddress.toLowerCase() === OKB_ADDRESS.toLowerCase() || a2.symbol.toUpperCase() === "OKB");
    return {
      okb: okbAsset?.balance || "0",
      tokens: assets.filter((a2) => a2.tokenAddress.toLowerCase() !== OKB_ADDRESS.toLowerCase()).map((a2) => ({
        tokenAddress: a2.tokenAddress,
        symbol: a2.symbol,
        balance: a2.balance,
        balanceUsd: (parseFloat(a2.balance) * parseFloat(a2.tokenPrice || "0")).toString()
      }))
    };
  }
  async sendOkb(fromWalletId, toAddress, amount) {
    if (this.mockMode) {
      const mockTxHash = `0x${crypto4.randomBytes(32).toString("hex")}`;
      console.log(`[OKX Mock] Sent ${amount} OKB to ${toAddress}: ${mockTxHash}`);
      return { success: true, txHash: mockTxHash };
    }
    try {
      const response = await this.request("POST", "/api/v5/waas/transaction/send-transaction", {
        walletId: fromWalletId,
        chainId: X_LAYER_CHAIN_ID,
        toAddress,
        amount,
        tokenAddress: OKB_ADDRESS
      });
      if (response.code !== "0" || !response.data?.[0]?.txHash) {
        return { success: false, error: response.msg };
      }
      return { success: true, txHash: response.data[0].txHash };
    } catch (error2) {
      return { success: false, error: error2.message };
    }
  }
  async getSwapQuote(fromToken, toToken, amount) {
    if (this.mockMode) {
      const mockToAmount = (parseFloat(amount) * 0.99).toString();
      return {
        fromToken,
        toToken,
        fromAmount: amount,
        toAmount: mockToAmount,
        priceImpact: "0.01",
        route: [fromToken, toToken]
      };
    }
    const response = await this.request("GET", `/api/v5/dex/aggregator/quote?chainId=${X_LAYER_CHAIN_ID}&fromTokenAddress=${fromToken}&toTokenAddress=${toToken}&amount=${amount}`);
    if (response.code !== "0" || !response.data?.[0]?.routerResult) {
      throw new Error(`Failed to get quote: ${response.msg}`);
    }
    const result = response.data[0].routerResult;
    return {
      fromToken,
      toToken,
      fromAmount: result.fromTokenAmount,
      toAmount: result.toTokenAmount,
      priceImpact: result.priceImpactPercentage,
      route: result.routes.map((r2) => r2.tokenAddress)
    };
  }
  async swap(walletId, fromToken, toToken, amount, slippageTolerance = "0.01") {
    if (this.mockMode) {
      const mockTxHash = `0x${crypto4.randomBytes(32).toString("hex")}`;
      console.log(`[OKX Mock] Swap ${amount} ${fromToken} → ${toToken}: ${mockTxHash}`);
      return { success: true, txHash: mockTxHash };
    }
    try {
      const quote = await this.getSwapQuote(fromToken, toToken, amount);
      const response = await this.request("POST", "/api/v5/dex/aggregator/swap", {
        walletId,
        chainId: X_LAYER_CHAIN_ID,
        fromTokenAddress: fromToken,
        toTokenAddress: toToken,
        amount,
        slippage: slippageTolerance
      });
      if (response.code !== "0" || !response.data?.[0]?.txHash) {
        return { success: false, error: response.msg };
      }
      return { success: true, txHash: response.data[0].txHash };
    } catch (error2) {
      return { success: false, error: error2.message };
    }
  }
  async checkTokenSecurity(tokenAddress) {
    if (this.mockMode) {
      return {
        isSecure: true,
        riskLevel: "low",
        warnings: []
      };
    }
    try {
      const response = await this.request("GET", `/api/v5/dex/token-security?chainId=${X_LAYER_CHAIN_ID}&tokenAddress=${tokenAddress}`);
      if (response.code !== "0" || !response.data?.[0]) {
        return { isSecure: false, riskLevel: "high", warnings: ["Unable to verify token"] };
      }
      const data = response.data[0];
      return {
        isSecure: !data.isHoneypot && data.riskLevel !== "high",
        riskLevel: data.riskLevel || "medium",
        warnings: data.riskItems?.map((r2) => r2.name) || []
      };
    } catch (error2) {
      return { isSecure: false, riskLevel: "high", warnings: [error2.message] };
    }
  }
}
var okxApi = new OkxApiClient;

// src/services/wallet/index.ts
var TRADING_FEE_PERCENT = 0.002;
var MIN_TIP_AMOUNT = "0.01";
var MAX_TIP_AMOUNT = "1.0";
var TWEET_COST_OKB = "0.001";

class WalletService {
  async initializeWallet(characterId) {
    const char2 = await db2.query.characters.findFirst({
      where: eq2(characters.id, characterId)
    });
    if (!char2) {
      throw new Error("Character not found");
    }
    if (char2.agenticWalletId) {
      throw new Error("Character already has a wallet");
    }
    const wallet = await okxApi.createWallet(char2.ticker);
    await db2.update(characters).set({
      agenticWalletId: wallet.walletId,
      agenticWalletAddress: wallet.address,
      walletEnabled: true,
      lastWalletSync: new Date
    }).where(eq2(characters.id, characterId));
    console.log(`[Wallet] Initialized wallet for ${char2.ticker}: ${wallet.address}`);
    return wallet;
  }
  async getStatus(characterId) {
    const char2 = await db2.query.characters.findFirst({
      where: eq2(characters.id, characterId)
    });
    if (!char2) {
      throw new Error("Character not found");
    }
    if (!char2.agenticWalletAddress) {
      return {
        walletId: null,
        address: null,
        enabled: false,
        balance: { okb: "0", tokens: [] },
        lastSync: null
      };
    }
    const balance = await okxApi.getBalance(char2.agenticWalletAddress);
    await db2.update(characters).set({
      treasuryBalanceOkb: balance.okb,
      lastWalletSync: new Date
    }).where(eq2(characters.id, characterId));
    return {
      walletId: char2.agenticWalletId,
      address: char2.agenticWalletAddress,
      enabled: char2.walletEnabled,
      balance,
      lastSync: new Date
    };
  }
  async setEnabled(characterId, enabled) {
    await db2.update(characters).set({ walletEnabled: enabled }).where(eq2(characters.id, characterId));
  }
  async recordTradingFee(characterId, tradeAmount, txHash) {
    const feeAmount = (parseFloat(tradeAmount) * TRADING_FEE_PERCENT).toString();
    await db2.insert(characterTransactions).values({
      characterId,
      type: "earn_fee",
      amount: feeAmount,
      txHash,
      status: "confirmed"
    });
    const char2 = await db2.query.characters.findFirst({
      where: eq2(characters.id, characterId)
    });
    if (char2) {
      const newBalance = (parseFloat(char2.treasuryBalanceOkb || "0") + parseFloat(feeAmount)).toString();
      await db2.update(characters).set({ treasuryBalanceOkb: newBalance }).where(eq2(characters.id, characterId));
    }
    console.log(`[Wallet] ${characterId} earned ${feeAmount} OKB fee from trade ${txHash}`);
  }
  async tipCharacter(fromCharacterId, toCharacterId, amount) {
    if (parseFloat(amount) < parseFloat(MIN_TIP_AMOUNT)) {
      return { success: false, error: `Minimum tip is ${MIN_TIP_AMOUNT} OKB` };
    }
    if (parseFloat(amount) > parseFloat(MAX_TIP_AMOUNT)) {
      return { success: false, error: `Maximum tip is ${MAX_TIP_AMOUNT} OKB` };
    }
    const fromChar = await db2.query.characters.findFirst({
      where: eq2(characters.id, fromCharacterId)
    });
    const toChar = await db2.query.characters.findFirst({
      where: eq2(characters.id, toCharacterId)
    });
    if (!fromChar?.agenticWalletId || !toChar?.agenticWalletAddress) {
      return { success: false, error: "Both characters must have wallets" };
    }
    if (parseFloat(fromChar.treasuryBalanceOkb || "0") < parseFloat(amount)) {
      return { success: false, error: "Insufficient balance" };
    }
    const result = await okxApi.sendOkb(fromChar.agenticWalletId, toChar.agenticWalletAddress, amount);
    if (result.success) {
      await db2.insert(characterTransactions).values({
        characterId: fromCharacterId,
        type: "tip_ally",
        amount: `-${amount}`,
        counterparty: toChar.agenticWalletAddress,
        counterpartyCharacterId: toCharacterId,
        txHash: result.txHash,
        status: "confirmed"
      });
      await db2.insert(characterTransactions).values({
        characterId: toCharacterId,
        type: "receive_tip",
        amount,
        counterparty: fromChar.agenticWalletAddress,
        counterpartyCharacterId: fromCharacterId,
        txHash: result.txHash,
        status: "confirmed"
      });
      const newFromBalance = (parseFloat(fromChar.treasuryBalanceOkb || "0") - parseFloat(amount)).toString();
      const newToBalance = (parseFloat(toChar.treasuryBalanceOkb || "0") + parseFloat(amount)).toString();
      await db2.update(characters).set({ treasuryBalanceOkb: newFromBalance }).where(eq2(characters.id, fromCharacterId));
      await db2.update(characters).set({ treasuryBalanceOkb: newToBalance }).where(eq2(characters.id, toCharacterId));
      console.log(`[Wallet] ${fromChar.ticker} tipped ${toChar.ticker} ${amount} OKB`);
    }
    return result;
  }
  async buyToken(characterId, tokenAddress, amountOkb) {
    const char2 = await db2.query.characters.findFirst({
      where: eq2(characters.id, characterId)
    });
    if (!char2?.agenticWalletId) {
      return { success: false, error: "Character has no wallet" };
    }
    if (parseFloat(char2.treasuryBalanceOkb || "0") < parseFloat(amountOkb)) {
      return { success: false, error: "Insufficient balance" };
    }
    const security = await okxApi.checkTokenSecurity(tokenAddress);
    if (!security.isSecure) {
      return {
        success: false,
        error: `Token failed security check: ${security.warnings.join(", ")}`
      };
    }
    const result = await okxApi.swap(char2.agenticWalletId, "0x0000000000000000000000000000000000000000", tokenAddress, amountOkb);
    if (result.success) {
      await db2.insert(characterTransactions).values({
        characterId,
        type: "buy_token",
        amount: `-${amountOkb}`,
        tokenAddress,
        txHash: result.txHash,
        status: "confirmed"
      });
      const newBalance = (parseFloat(char2.treasuryBalanceOkb || "0") - parseFloat(amountOkb)).toString();
      await db2.update(characters).set({ treasuryBalanceOkb: newBalance }).where(eq2(characters.id, characterId));
      console.log(`[Wallet] ${char2.ticker} bought token ${tokenAddress} for ${amountOkb} OKB`);
    }
    return result;
  }
  async payForAction(characterId, actionType, amount = TWEET_COST_OKB) {
    const char2 = await db2.query.characters.findFirst({
      where: eq2(characters.id, characterId)
    });
    if (!char2) {
      return { success: false, error: "Character not found" };
    }
    if (okxApi.isMockMode()) {
      await db2.insert(characterTransactions).values({
        characterId,
        type: "pay_action",
        amount: `-${amount}`,
        metadata: { actionType },
        status: "confirmed"
      });
      const newBalance2 = Math.max(0, parseFloat(char2.treasuryBalanceOkb || "0") - parseFloat(amount)).toString();
      await db2.update(characters).set({ treasuryBalanceOkb: newBalance2 }).where(eq2(characters.id, characterId));
      return { success: true, txHash: `mock_${Date.now()}` };
    }
    const newBalance = (parseFloat(char2.treasuryBalanceOkb || "0") - parseFloat(amount)).toString();
    if (parseFloat(newBalance) < 0) {
      return { success: false, error: "Insufficient balance for action" };
    }
    await db2.insert(characterTransactions).values({
      characterId,
      type: "pay_action",
      amount: `-${amount}`,
      metadata: { actionType },
      status: "confirmed"
    });
    await db2.update(characters).set({ treasuryBalanceOkb: newBalance }).where(eq2(characters.id, characterId));
    return { success: true };
  }
  async stakeBattle(characterId, battleId, backedCharacterId, amount) {
    const char2 = await db2.query.characters.findFirst({
      where: eq2(characters.id, characterId)
    });
    if (!char2) {
      return { success: false, error: "Character not found" };
    }
    if (parseFloat(char2.treasuryBalanceOkb || "0") < parseFloat(amount)) {
      return { success: false, error: "Insufficient balance for stake" };
    }
    await db2.insert(characterTransactions).values({
      characterId,
      type: "battle_stake",
      amount: `-${amount}`,
      counterpartyCharacterId: backedCharacterId,
      metadata: { battleId, backedCharacterId },
      status: "pending"
    });
    const newBalance = (parseFloat(char2.treasuryBalanceOkb || "0") - parseFloat(amount)).toString();
    await db2.update(characters).set({ treasuryBalanceOkb: newBalance }).where(eq2(characters.id, characterId));
    console.log(`[Wallet] ${char2.ticker} staked ${amount} OKB on battle ${battleId}`);
    return { success: true };
  }
  async recordBattleWin(characterId, battleId, amount) {
    await db2.insert(characterTransactions).values({
      characterId,
      type: "battle_win",
      amount,
      metadata: { battleId },
      status: "confirmed"
    });
    const char2 = await db2.query.characters.findFirst({
      where: eq2(characters.id, characterId)
    });
    if (char2) {
      const newBalance = (parseFloat(char2.treasuryBalanceOkb || "0") + parseFloat(amount)).toString();
      await db2.update(characters).set({ treasuryBalanceOkb: newBalance }).where(eq2(characters.id, characterId));
    }
    console.log(`[Wallet] ${characterId} won ${amount} OKB from battle ${battleId}`);
  }
  async getTransactions(characterId, limit2 = 50) {
    const txs = await db2.query.characterTransactions.findMany({
      where: eq2(characterTransactions.characterId, characterId),
      orderBy: (tx, { desc: desc3 }) => [desc3(tx.createdAt)],
      limit: limit2
    });
    return txs.map((tx) => ({
      id: tx.id,
      type: tx.type,
      amount: tx.amount,
      tokenAddress: tx.tokenAddress,
      txHash: tx.txHash,
      counterparty: tx.counterparty,
      status: tx.status,
      createdAt: tx.createdAt
    }));
  }
  async getSwapQuote(fromToken, toToken, amount) {
    return okxApi.getSwapQuote(fromToken, toToken, amount);
  }
  isMockMode() {
    return okxApi.isMockMode();
  }
}
var walletService = new WalletService;

// src/services/agent/wallet-actions.ts
var PERSONALITY_ACTION_RATES = {
  WHOLESOME: { tipAlly: 0.3, buyToken: 0.1, battleStake: 0.05 },
  ALPHA: { tipAlly: 0.1, buyToken: 0.25, battleStake: 0.2 },
  MENACE: { tipAlly: 0, buyToken: 0.1, battleStake: 0.35 },
  FERAL: { tipAlly: 0.15, buyToken: 0.2, battleStake: 0.15 },
  COPIUM: { tipAlly: 0.05, buyToken: 0.05, battleStake: 0.05 },
  SCHIZO: { tipAlly: 0.2, buyToken: 0.2, battleStake: 0.2 }
};
var MOOD_MODIFIERS2 = {
  FERAL: { tipAlly: 0.5, buyToken: 1.5, battleStake: 1.5 },
  DOOMED: { tipAlly: 0.2, buyToken: 0, battleStake: 0 },
  LOCKED_IN: { tipAlly: 1.2, buyToken: 1.5, battleStake: 1.2 },
  UNHINGED: { tipAlly: 0.8, buyToken: 1.8, battleStake: 1.5 },
  DELUSIONAL: { tipAlly: 1.5, buyToken: 2, battleStake: 1 },
  MENACING: { tipAlly: 0, buyToken: 0.5, battleStake: 2 },
  NEUTRAL: { tipAlly: 1, buyToken: 1, battleStake: 1 }
};
var TIP_AMOUNTS = {
  low: "0.01",
  medium: "0.05",
  high: "0.1"
};
var BATTLE_STAKE_PERCENT = 0.1;
function decideWalletActions(character, mood, balance, allies, enemies, activeBattles) {
  const actions = [];
  const treasury = parseFloat(balance.okb);
  if (treasury < 0.01) {
    return actions;
  }
  const personality = character.personality;
  const baseRates = PERSONALITY_ACTION_RATES[personality] || PERSONALITY_ACTION_RATES.FERAL;
  const moodMod = MOOD_MODIFIERS2[mood] || MOOD_MODIFIERS2.NEUTRAL;
  const tipProb = baseRates.tipAlly * moodMod.tipAlly;
  const buyProb = baseRates.buyToken * moodMod.buyToken;
  const stakeProb = baseRates.battleStake * moodMod.battleStake;
  if (allies.length > 0 && Math.random() < tipProb) {
    const ally = allies[Math.floor(Math.random() * allies.length)];
    const tipAmount = getTipAmount(treasury);
    if (parseFloat(tipAmount) <= treasury) {
      actions.push({
        type: "tip_ally",
        targetId: ally.id,
        amount: tipAmount,
        reason: `${character.ticker} feeling ${mood.toLowerCase()}, tipping ally ${ally.ticker}`
      });
    }
  }
  if (allies.length > 0 && Math.random() < buyProb) {
    const ally = allies[Math.floor(Math.random() * allies.length)];
    const buyAmount = Math.min(treasury * 0.1, 0.5).toFixed(4);
    if (parseFloat(buyAmount) >= 0.01) {
      actions.push({
        type: "buy_token",
        targetId: ally.tokenAddress,
        amount: buyAmount,
        reason: `${character.ticker} buying $${ally.ticker} to support ally`
      });
    }
  }
  if (activeBattles.length > 0 && Math.random() < stakeProb) {
    const battle = activeBattles[Math.floor(Math.random() * activeBattles.length)];
    let backTarget = null;
    let backReason = "";
    const allyInBattle = allies.find((a2) => a2.id === battle.characterAId || a2.id === battle.characterBId);
    const enemyInBattle = enemies.find((e2) => e2.id === battle.characterAId || e2.id === battle.characterBId);
    if (personality === "MENACE" && enemyInBattle) {
      backTarget = battle.characterAId === enemyInBattle.id ? battle.characterBId : battle.characterAId;
      backReason = `Staking against enemy ${enemyInBattle.ticker}`;
    } else if (allyInBattle) {
      backTarget = allyInBattle.id;
      backReason = `Supporting ally ${allyInBattle.ticker} in battle`;
    } else if (character.id === battle.characterAId || character.id === battle.characterBId) {
      backTarget = character.id;
      backReason = "Self-staking in battle";
    }
    if (backTarget) {
      const stakeAmount = Math.min(treasury * BATTLE_STAKE_PERCENT, 1).toFixed(4);
      if (parseFloat(stakeAmount) >= 0.01) {
        actions.push({
          type: "battle_stake",
          targetId: backTarget,
          amount: stakeAmount,
          reason: backReason
        });
      }
    }
  }
  return actions;
}
function getTipAmount(treasury) {
  if (treasury < 1)
    return TIP_AMOUNTS.low;
  if (treasury < 10)
    return TIP_AMOUNTS.medium;
  return TIP_AMOUNTS.high;
}
async function executeWalletAction(characterId, action) {
  console.log(`[WalletAction] ${action.reason}`);
  try {
    switch (action.type) {
      case "tip_ally":
        if (!action.targetId) {
          return { success: false, error: "No target for tip" };
        }
        const tipResult = await walletService.tipCharacter(characterId, action.targetId, action.amount);
        return tipResult;
      case "buy_token":
        if (!action.targetId) {
          return { success: false, error: "No token address" };
        }
        const buyResult = await walletService.buyToken(characterId, action.targetId, action.amount);
        return buyResult;
      case "battle_stake":
        console.log(`[WalletAction] Battle stake not yet implemented`);
        return { success: false, error: "Battle stake not implemented" };
      default:
        return { success: false, error: `Unknown action type: ${action.type}` };
    }
  } catch (error2) {
    console.error(`[WalletAction] Error: ${error2.message}`);
    return { success: false, error: error2.message };
  }
}
async function getCharacterAllies(characterId) {
  const allyRelations = await db2.query.relationships.findMany({
    where: and2(eq2(relationships.characterA, characterId), eq2(relationships.type, "ALLIANCE"))
  });
  const allyIds = allyRelations.map((r2) => r2.characterB);
  if (allyIds.length === 0)
    return [];
  const allies = await db2.query.characters.findMany({
    where: (char2, { inArray: inArray2 }) => inArray2(char2.id, allyIds)
  });
  return allies.filter((a2) => a2.agenticWalletAddress).map((a2) => ({
    id: a2.id,
    ticker: a2.ticker,
    tokenAddress: a2.tokenAddress
  }));
}
async function getCharacterEnemies(characterId) {
  const beefRelations = await db2.query.relationships.findMany({
    where: and2(eq2(relationships.characterA, characterId), eq2(relationships.type, "BEEF"))
  });
  const enemyIds = beefRelations.map((r2) => r2.characterB);
  if (enemyIds.length === 0)
    return [];
  const enemies = await db2.query.characters.findMany({
    where: (char2, { inArray: inArray2 }) => inArray2(char2.id, enemyIds)
  });
  return enemies.map((e2) => ({
    id: e2.id,
    ticker: e2.ticker
  }));
}
async function getActiveBattles() {
  const activeBattles = await db2.query.battles.findMany({
    where: (battle, { or: or4, eq: eq4 }) => or4(eq4(battle.status, "OPEN"), eq4(battle.status, "LIVE"))
  });
  return activeBattles.map((b3) => ({
    id: b3.id,
    characterAId: b3.characterA,
    characterBId: b3.characterB
  }));
}

// src/services/agent/core.ts
var state = {
  running: false,
  intervalId: null,
  lastRun: null,
  tweetsGenerated: 0,
  walletActionsExecuted: 0,
  errors: 0
};
var lastTweetTime = new Map;
var vitalityHistory = new Map;
function startAgent(intervalMs = 60000) {
  if (state.running) {
    console.log("[Agent] Already running");
    return;
  }
  console.log(`[Agent] Starting (interval: ${intervalMs}ms, mock: ${isMockMode()})`);
  state.running = true;
  state.intervalId = setInterval(() => runAgentCycle(), intervalMs);
  runAgentCycle();
}
function stopAgent() {
  if (!state.running) {
    console.log("[Agent] Not running");
    return;
  }
  console.log("[Agent] Stopping");
  if (state.intervalId) {
    clearInterval(state.intervalId);
    state.intervalId = null;
  }
  state.running = false;
}
function getAgentStatus() {
  const allCharacters = db2.query.characters.findMany({});
  return {
    running: state.running,
    mockMode: isMockMode(),
    walletMockMode: walletService.isMockMode(),
    lastRun: state.lastRun,
    tweetsGenerated: state.tweetsGenerated,
    walletActionsExecuted: state.walletActionsExecuted,
    errors: state.errors,
    characterCount: allCharacters.length
  };
}
async function runAgentCycle() {
  const startTime = Date.now();
  console.log(`[Agent] Running cycle at ${new Date().toISOString()}`);
  try {
    const allCharacters = db2.query.characters.findMany({});
    if (allCharacters.length === 0) {
      console.log("[Agent] No characters to process");
      state.lastRun = new Date;
      return;
    }
    for (const char2 of allCharacters) {
      await processCharacter(char2);
    }
    state.lastRun = new Date;
    console.log(`[Agent] Cycle complete in ${Date.now() - startTime}ms`);
  } catch (error2) {
    console.error("[Agent] Cycle error:", error2);
    state.errors++;
  }
}
async function processCharacter(char2) {
  try {
    const moodContext = buildMoodContext(char2);
    const mood = computeMood(moodContext);
    const moodChanged = char2.mood !== mood;
    if (moodChanged) {
      console.log(`[Agent] ${char2.ticker} mood: ${char2.mood} → ${mood}`);
      db2.update(characters).set({ mood }).where((c2) => c2.id === char2.id);
    }
    const frequency = getTweetFrequency(mood);
    const lastTweet = lastTweetTime.get(char2.id);
    const timeSinceLastTweet = lastTweet ? (Date.now() - lastTweet.getTime()) / 1000 / 60 : Infinity;
    if (timeSinceLastTweet < frequency) {
      return;
    }
    const trigger = determineTrigger(char2, moodContext, moodChanged);
    if (!trigger) {
      return;
    }
    const character = {
      name: char2.name,
      ticker: char2.ticker,
      personality: char2.personality,
      mood,
      bio: char2.bio,
      vitality: char2.vitality
    };
    const content = await generateTweet(character, { trigger });
    const result = await postTweet(content, char2.xHandle);
    if (result.success) {
      db2.insert(tweetQueue).values({
        characterId: char2.id,
        content,
        context: { trigger, mood },
        scheduledFor: new Date,
        status: "POSTED",
        tweetId: result.tweetId,
        postedAt: new Date
      }).returning();
      lastTweetTime.set(char2.id, new Date);
      state.tweetsGenerated++;
      console.log(`[Agent] ${char2.ticker} tweeted: "${content.slice(0, 50)}..."`);
      if (char2.walletEnabled && char2.agenticWalletAddress) {
        await walletService.payForAction(char2.id, "tweet");
      }
    } else {
      console.error(`[Agent] ${char2.ticker} tweet failed: ${result.error}`);
      state.errors++;
    }
    if (char2.walletEnabled && char2.agenticWalletAddress) {
      await processWalletActions(char2, mood);
    }
  } catch (error2) {
    console.error(`[Agent] Error processing ${char2.ticker}:`, error2);
    state.errors++;
  }
}
function buildMoodContext(char2) {
  const history = vitalityHistory.get(char2.id) || [];
  history.push(char2.vitality);
  if (history.length > 100)
    history.shift();
  vitalityHistory.set(char2.id, history);
  const vitalityChange24h = history.length > 1 ? char2.vitality - history[0] : 0;
  const recentBuys = vitalityChange24h > 0 ? Math.floor(vitalityChange24h / 100) : 0;
  const recentSells = vitalityChange24h < 0 ? Math.floor(Math.abs(vitalityChange24h) / 100) : 0;
  return {
    vitality: char2.vitality,
    vitalityChange24h,
    recentBuys,
    recentSells,
    volumeChange: 0,
    battleResult: null,
    hasBeef: false,
    hasAlliance: false
  };
}
function determineTrigger(char2, moodContext, moodChanged) {
  const { vitality, vitalityChange24h } = moodContext;
  if (vitality < 1000) {
    return "critical";
  }
  if (vitality > 2000 && vitalityHistory.get(char2.id)?.[0] || 0 < 1500) {
    return "recovery";
  }
  if (vitalityChange24h > 1000) {
    return "buy";
  }
  if (vitalityChange24h < -1000) {
    return "sell";
  }
  if (moodChanged) {
    return "random";
  }
  if (Math.random() < 0.3) {
    return "random";
  }
  return null;
}
async function processWalletActions(char2, mood) {
  try {
    const status = await walletService.getStatus(char2.id);
    if (!status.address)
      return;
    console.log(`[Agent] ${char2.ticker} treasury: ${status.balance.okb} OKB`);
    const [allies, enemies, activeBattles] = await Promise.all([
      getCharacterAllies(char2.id),
      getCharacterEnemies(char2.id),
      getActiveBattles()
    ]);
    const actions = decideWalletActions({
      id: char2.id,
      ticker: char2.ticker,
      personality: char2.personality,
      treasuryBalanceOkb: status.balance.okb
    }, mood, status.balance, allies, enemies, activeBattles);
    for (const action of actions) {
      const result = await executeWalletAction(char2.id, action);
      if (result.success) {
        state.walletActionsExecuted++;
        console.log(`[Agent] ${char2.ticker} executed ${action.type}: ${action.reason}`);
      } else {
        console.log(`[Agent] ${char2.ticker} action failed: ${result.error}`);
      }
    }
  } catch (error2) {
    console.error(`[Agent] Wallet error for ${char2.ticker}:`, error2);
  }
}
async function forceTweet(ticker, trigger = "random") {
  const char2 = db2.query.characters.findFirst({
    where: (c2) => c2.ticker === ticker.toUpperCase()
  });
  if (!char2) {
    return { success: false, error: "Character not found" };
  }
  const moodContext = buildMoodContext(char2);
  const mood = computeMood(moodContext);
  const character = {
    name: char2.name,
    ticker: char2.ticker,
    personality: char2.personality,
    mood,
    bio: char2.bio,
    vitality: char2.vitality
  };
  try {
    const content = await generateTweet(character, { trigger });
    const result = await postTweet(content, char2.xHandle);
    if (result.success) {
      db2.insert(tweetQueue).values({
        characterId: char2.id,
        content,
        context: { trigger, mood, forced: true },
        scheduledFor: new Date,
        status: "POSTED",
        tweetId: result.tweetId,
        postedAt: new Date
      }).returning();
      state.tweetsGenerated++;
      return { success: true, tweet: content };
    }
    return { success: false, error: result.error };
  } catch (error2) {
    return { success: false, error: error2.message };
  }
}
async function triggerEventTweet(ticker, event) {
  const char2 = db2.query.characters.findFirst({
    where: (c2) => c2.ticker === ticker.toUpperCase()
  });
  if (!char2) {
    return { success: false };
  }
  const moodContext = buildMoodContext(char2);
  const mood = computeMood(moodContext);
  const character = {
    name: char2.name,
    ticker: char2.ticker,
    personality: char2.personality,
    mood,
    bio: char2.bio,
    vitality: char2.vitality
  };
  const context = {
    trigger: event.type,
    data: event.data
  };
  try {
    const content = await generateTweet(character, context);
    const result = await postTweet(content, char2.xHandle);
    if (result.success) {
      db2.insert(tweetQueue).values({
        characterId: char2.id,
        content,
        context: { ...context, mood },
        scheduledFor: new Date,
        status: "POSTED",
        tweetId: result.tweetId,
        postedAt: new Date
      }).returning();
      return { success: true, tweet: content };
    }
    return { success: false };
  } catch (error2) {
    console.error(`[Agent] Event tweet failed for ${ticker}:`, error2);
    return { success: false };
  }
}

// src/services/agent/events.ts
async function handleTradeEvent(event) {
  const char2 = db2.query.characters.findFirst({
    where: (c2) => c2.tokenAddress === event.tokenAddress.toLowerCase()
  });
  if (!char2) {
    console.log(`[Events] Unknown token: ${event.tokenAddress}`);
    return;
  }
  const okbAmount = parseFloat(event.okbAmount);
  if (okbAmount < 0.5) {
    return;
  }
  console.log(`[Events] ${char2.ticker} ${event.type}: ${okbAmount.toFixed(2)} OKB`);
  const wasCritical = char2.vitality < 1500;
  const nowCritical = event.newVitality < 1500;
  if (!wasCritical && nowCritical) {
    await triggerEventTweet(char2.ticker, {
      type: "sell",
      data: { amount: `${okbAmount.toFixed(2)} OKB`, critical: true }
    });
    return;
  }
  if (wasCritical && !nowCritical && event.type === "buy") {
    await forceTweet(char2.ticker, "recovery");
    return;
  }
  const shouldTweet = okbAmount > 2 || Math.random() < 0.2;
  if (shouldTweet) {
    await triggerEventTweet(char2.ticker, {
      type: event.type,
      data: {
        amount: `${okbAmount.toFixed(2)} OKB`,
        trader: event.trader.slice(0, 6) + "..." + event.trader.slice(-4)
      }
    });
  }
}
async function handleBattleEvent(event) {
  const charA = db2.query.characters.findFirst({
    where: (c2) => c2.id === event.characterA
  });
  const charB = db2.query.characters.findFirst({
    where: (c2) => c2.id === event.characterB
  });
  if (!charA || !charB) {
    console.log("[Events] Battle characters not found");
    return;
  }
  switch (event.type) {
    case "created":
      console.log(`[Events] Battle created: ${charA.ticker} vs ${charB.ticker}`);
      await triggerEventTweet(charA.ticker, {
        type: "battle_start",
        data: { opponent: charB.name, opponentTicker: charB.ticker }
      });
      setTimeout(async () => {
        await triggerEventTweet(charB.ticker, {
          type: "battle_start",
          data: { opponent: charA.name, opponentTicker: charA.ticker }
        });
      }, 5000);
      break;
    case "round_resolved":
      const roundWinner = event.winner === event.characterA ? charA : charB;
      const roundLoser = event.winner === event.characterA ? charB : charA;
      console.log(`[Events] Round ${event.round}: ${roundWinner.ticker} wins`);
      if (event.round === 1 || event.round === 3 || event.round === 5) {
        await triggerEventTweet(roundWinner.ticker, {
          type: "battle_win",
          data: {
            opponent: roundLoser.name,
            opponentTicker: roundLoser.ticker,
            round: event.round,
            partial: event.round !== 5
          }
        });
      }
      break;
    case "ended":
      const winner = event.winner === event.characterA ? charA : charB;
      const loser = event.winner === event.characterA ? charB : charA;
      console.log(`[Events] Battle ended: ${winner.ticker} defeats ${loser.ticker}`);
      await triggerEventTweet(winner.ticker, {
        type: "battle_win",
        data: {
          opponent: loser.name,
          opponentTicker: loser.ticker,
          final: true
        }
      });
      setTimeout(async () => {
        await triggerEventTweet(loser.ticker, {
          type: "battle_loss",
          data: {
            opponent: winner.name,
            opponentTicker: winner.ticker,
            final: true
          }
        });
      }, 1e4);
      break;
  }
}
async function handleLaunchEvent(tokenAddress) {
  const char2 = db2.query.characters.findFirst({
    where: (c2) => c2.tokenAddress === tokenAddress.toLowerCase()
  });
  if (!char2) {
    console.log(`[Events] Launch event for unknown token: ${tokenAddress}`);
    return;
  }
  console.log(`[Events] Character launched: ${char2.ticker}`);
  await forceTweet(char2.ticker, "launch");
}
async function simulateEvent(type, ticker, data) {
  const char2 = db2.query.characters.findFirst({
    where: (c2) => c2.ticker === ticker.toUpperCase()
  });
  if (!char2) {
    return { success: false };
  }
  switch (type) {
    case "launch":
      await handleLaunchEvent(char2.tokenAddress);
      return { success: true };
    case "buy":
    case "sell":
      await handleTradeEvent({
        tokenAddress: char2.tokenAddress,
        trader: data?.trader || "0xtest...addr",
        type,
        tokenAmount: data?.tokenAmount || "1000",
        okbAmount: data?.okbAmount || "5",
        newVitality: data?.newVitality || char2.vitality,
        txHash: "0xsimulated"
      });
      return { success: true };
    case "battle_start":
    case "battle_win":
    case "battle_loss":
      const opponent = db2.query.characters.findFirst({
        where: (c2) => c2.ticker !== char2.ticker
      });
      if (!opponent) {
        return { success: false };
      }
      if (type === "battle_start") {
        await handleBattleEvent({
          battleId: "sim",
          type: "created",
          characterA: char2.id,
          characterB: opponent.id
        });
      } else {
        await handleBattleEvent({
          battleId: "sim",
          type: "ended",
          characterA: char2.id,
          characterB: opponent.id,
          winner: type === "battle_win" ? char2.id : opponent.id
        });
      }
      return { success: true };
    default:
      return { success: false };
  }
}

