var forceTweetSchema = exports_external.object({
  ticker: exports_external.string(),
  trigger: exports_external.enum([
    "launch",
    "buy",
    "sell",
    "battle_start",
    "battle_win",
    "battle_loss",
    "beef",
    "alliance",
    "critical",
    "recovery",
    "random",
    "reply"
  ]).optional()
});
agentRoutes.post("/tweet", zValidator("json", forceTweetSchema), async (c2) => {
  const { ticker, trigger = "random" } = c2.req.valid("json");
  const result = await forceTweet(ticker, trigger);
  if (result.success) {
    return c2.json({ success: true, tweet: result.tweet });
  }
  return c2.json({ success: false, error: result.error }, 400);
});
var simulateSchema = exports_external.object({
  ticker: exports_external.string(),
  event: exports_external.enum(["buy", "sell", "battle_start", "battle_win", "battle_loss", "launch"]),
  data: exports_external.any().optional()
});
agentRoutes.post("/simulate", zValidator("json", simulateSchema), async (c2) => {
  const { ticker, event, data } = c2.req.valid("json");
  const result = await simulateEvent(event, ticker, data);
  return c2.json(result);
});
agentRoutes.get("/mock-tweets", (c2) => {
  if (!isMockMode()) {
    return c2.json({ error: "Not in mock mode" }, 400);
  }
  const tweets = getMockTweets();
  return c2.json({ tweets, count: tweets.length });
});
agentRoutes.delete("/mock-tweets", (c2) => {
  if (!isMockMode()) {
    return c2.json({ error: "Not in mock mode" }, 400);
  }
  clearMockTweets();
  return c2.json({ success: true });
});
agentRoutes.post("/bulk-tweet", async (c2) => {
  const trigger = c2.req.query("trigger") || "random";
  const allCharacters = db2.query.characters.findMany({});
  const results = [];
  for (const char2 of allCharacters) {
    const result = await forceTweet(char2.ticker, trigger);
    results.push({
      ticker: char2.ticker,
      success: result.success,
      tweet: result.tweet
    });
  }
  return c2.json({ results, count: results.length });
});
var battleTweetSchema = exports_external.object({
  battleId: exports_external.string(),
  type: exports_external.enum(["start", "round", "end"]),
  round: exports_external.number().optional(),
  winner: exports_external.string().optional()
});
agentRoutes.post("/battle-tweet", zValidator("json", battleTweetSchema), async (c2) => {
  const { battleId, type, round, winner } = c2.req.valid("json");
  const battle = db2.query.battles.findFirst({
    where: (b3) => b3.id === battleId || b3.onChainId?.toString() === battleId
  });
  if (!battle) {
    return c2.json({ error: "Battle not found" }, 404);
  }
  const charA = db2.query.characters.findFirst({ where: (ch) => ch.id === battle.characterA });
  const charB = db2.query.characters.findFirst({ where: (ch) => ch.id === battle.characterB });
  if (!charA || !charB) {
    return c2.json({ error: "Battle characters not found" }, 404);
  }
  const results = [];
  switch (type) {
    case "start":
      const resultA = await triggerEventTweet(charA.ticker, {
        type: "battle_start",
        data: { opponent: charB.name, opponentTicker: charB.ticker }
      });
      results.push({ ticker: charA.ticker, tweet: resultA.tweet });
      const resultB = await triggerEventTweet(charB.ticker, {
        type: "battle_start",
        data: { opponent: charA.name, opponentTicker: charA.ticker }
      });
      results.push({ ticker: charB.ticker, tweet: resultB.tweet });
      break;
    case "round":
      if (!winner) {
        return c2.json({ error: "Winner ticker required for round tweets" }, 400);
      }
      const roundWinner = winner === charA.ticker ? charA : charB;
      const roundLoser = winner === charA.ticker ? charB : charA;
      const roundResult = await triggerEventTweet(roundWinner.ticker, {
        type: "battle_win",
        data: { opponent: roundLoser.name, opponentTicker: roundLoser.ticker, round }
      });
      results.push({ ticker: roundWinner.ticker, tweet: roundResult.tweet });
      break;
    case "end":
      if (!winner) {
        return c2.json({ error: "Winner ticker required for end tweets" }, 400);
      }
      const finalWinner = winner === charA.ticker ? charA : charB;
      const finalLoser = winner === charA.ticker ? charB : charA;
      const winResult = await triggerEventTweet(finalWinner.ticker, {
        type: "battle_win",
        data: { opponent: finalLoser.name, opponentTicker: finalLoser.ticker, final: true }
      });
      results.push({ ticker: finalWinner.ticker, tweet: winResult.tweet });
      const loseResult = await triggerEventTweet(finalLoser.ticker, {
        type: "battle_loss",
        data: { opponent: finalWinner.name, opponentTicker: finalWinner.ticker, final: true }
      });
      results.push({ ticker: finalLoser.ticker, tweet: loseResult.tweet });
      break;
  }
  return c2.json({ success: true, results });
});

